#!/bin/bash
whois "$1" | awk -F': ' 'BEGIN{split("Registrant,Admin,Tech",t,",");split("Name,Organization,Street,City,State/Province,Postal Code,Country,Phone,Phone Ext,Fax,Fax Ext,Email",f,",")}{gsub(/\r/,"",$2);gsub(/^[ \t]+/,"",$2);a[$1]=$2}END{for(i=1;i<=3;i++)for(j=1;j<=12;j++){k=t[i]" "f[j];v=a[k];if(f[j]=="Street"&&v!="")v=v" ";k1=k;if(f[j]~/Ext/)k1=k1":";s=s k1 "," v (i==3&&j==12?"":"\n")}printf "%s", s}' > "$1.csv"
